requests.testScript:
pw.env.set("TEST_ORDER", "req-with-import");
pw.test("top-level ESM import in pre-request script resolved", () => {
  pw.expect(pw.env.get("IMPORTED_VALUE")).toBe("esm-import-ok");
});
pw.test("cascade order preserved with import-using request", () => {
  pw.expect(pw.env.get("PRE_ORDER")).toBe("root->target-folder->req-with-import");
});

import lodash from "data:text/javascript,export default { pick: (obj, keys) => keys.reduce((acc, k) => (k in obj ? Object.assign(acc, { [k]: obj[k] }) : acc), {}) }";
import axios from "data:text/javascript,export default { name: 'axios-stub', version: '1.6.0' }";
import { format } from "data:text/javascript,export const format = (_d, fmt) => fmt.replace('yyyy', '2026').replace('MM', '05').replace('dd', '07')";
import * as ns from "data:text/javascript,export const a = 1; export const b = 2";
import combo, { tag } from "data:text/javascript,export default 7; export const tag = 'mixed'";
const picked = lodash.pick({ id: 1, name: "hopp", email: "x@y.z", extra: "drop" }, ["id", "name", "email"]);
pw.env.set("TEST_IMPORT_PICKED", JSON.stringify(picked));
pw.env.set("TEST_IMPORT_AXIOS", axios.name);
pw.env.set("TEST_IMPORT_FORMATTED", format(new Date(), "yyyy-MM-dd"));
pw.env.set("TEST_IMPORT_NAMESPACE_SUM", String(ns.a + ns.b));
pw.env.set("TEST_IMPORT_MIXED", String(combo) + "-" + tag);
pw.env.set("TEST_ORDER", "req-with-test-import");
pw.test("test-script default imports resolve", () => {
  pw.expect(pw.env.get("TEST_IMPORT_AXIOS")).toBe("axios-stub");
});
pw.test("test-script named import resolves", () => {
  pw.expect(pw.env.get("TEST_IMPORT_FORMATTED")).toBe("2026-05-07");
});
pw.test("test-script namespace import resolves", () => {
  pw.expect(pw.env.get("TEST_IMPORT_NAMESPACE_SUM")).toBe("3");
});
pw.test("test-script mixed default and named import resolves", () => {
  pw.expect(pw.env.get("TEST_IMPORT_MIXED")).toBe("7-mixed");
});
pw.test("test-script imports run alongside test logic", () => {
  pw.expect(pw.env.get("TEST_IMPORT_PICKED")).toBe(JSON.stringify({ id: 1, name: "hopp", email: "x@y.z" }));
});

pw.env.set("TEST_ORDER", "sibling-req-in-sibling");
pw.test("sibling-folder cascade is root->sibling-folder->this-request (no target-folder leak)", () => {
  pw.expect(pw.env.get("PRE_ORDER")).toBe("root->sibling-folder->sibling-req-in-sibling");
});
pw.test("target-folder pre-script ran once per request in target-folder", () => {
  pw.expect(pw.env.get("TARGET_FOLDER_RUN_COUNT")).toBe("4");
});

testScript:
